import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { employeeAPI } from '../services/api';
import toast from 'react-hot-toast';

const MOCK = [
  {id:'EMP2401',name:'Sunita Sharma',type:'Teacher',dept:'Mathematics',phone:'9000000003',salary:'₹42,000',active:true},
  {id:'EMP2402',name:'Ramesh Yadav',type:'Teacher',dept:'Science',phone:'9000000004',salary:'₹38,000',active:true},
  {id:'EMP2403',name:'Kavita Mishra',type:'Accountant',dept:'Finance',phone:'9000000005',salary:'₹35,000',active:true},
  {id:'EMP2404',name:'Dinesh Kumar',type:'Driver',dept:'Transport',phone:'9543210987',salary:'₹22,000',active:true},
  {id:'EMP2405',name:'Anjali Singh',type:'Receptionist',dept:'Administration',phone:'9000000006',salary:'₹28,000',active:true},
];

const TYPE_COLORS = {Teacher:'#EDE9F8|#2D1B69',Accountant:'#FEF3C7|#92400E',Driver:'#F3F4F6|#374151',Receptionist:'#E0F2FE|#0369A1'};

export default function Employees() {
  const [search, setSearch] = useState('');
  const filtered = MOCK.filter(e => e.name.toLowerCase().includes(search.toLowerCase()) || e.id.includes(search));

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div><h2 style={{fontSize:20,fontWeight:700}}>Employees</h2><p style={{fontSize:12,color:'#6B7280',marginTop:2}}>87 staff members</p></div>
        <button onClick={()=>toast.success('Add Employee form — connect to backend')} style={{padding:'8px 18px',background:'#2D1B69',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:600,cursor:'pointer'}}>+ Add Employee</button>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'repeat(5,1fr)',gap:12,marginBottom:16}}>
        {[['52','Teachers','#EDE9F8','#2D1B69'],['8','Admin','#D1FAE5','#065F46'],['12','Support','#FEF3C7','#92400E'],['6','Drivers','#E0F2FE','#0369A1'],['9','Other','#FEE2E2','#991B1B']].map(([v,l,bg,c])=>(
          <div key={l} style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:12,padding:14}}>
            <div style={{fontSize:22,fontWeight:700,color:c,lineHeight:1,marginBottom:4}}>{v}</div>
            <div style={{fontSize:11,color:'#6B7280'}}>{l}</div>
          </div>
        ))}
      </div>

      <div style={{marginBottom:14}}>
        <input placeholder="🔍 Search name, employee ID…" value={search} onChange={e=>setSearch(e.target.value)}
          style={{padding:'8px 12px',border:'1px solid #E5E7EB',borderRadius:8,fontSize:12,width:280,outline:'none'}}/>
      </div>

      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Emp. ID','Name','Role','Department','Phone','Basic Salary','Status','Action'].map(h=>(
              <th key={h} style={{padding:'9px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:600,textTransform:'uppercase',borderBottom:'0.5px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {filtered.map(e=>{
              const [bg,c]=(TYPE_COLORS[e.type]||'#F3F4F6|#374151').split('|');
              return (
                <tr key={e.id} style={{borderBottom:'0.5px solid #F3F4F6'}}>
                  <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{e.id}</td>
                  <td style={{padding:'10px 12px'}}>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <div style={{width:28,height:28,borderRadius:7,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#2D1B69'}}>{e.name[0]}</div>
                      <span style={{fontWeight:600}}>{e.name}</span>
                    </div>
                  </td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:bg,color:c}}>{e.type}</span></td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.dept}</td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.phone}</td>
                  <td style={{padding:'10px 12px',fontWeight:600}}>{e.salary}</td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#D1FAE5',color:'#065F46'}}>Active</span></td>
                  <td style={{padding:'10px 12px'}}><button onClick={()=>toast(`Viewing ${e.name}`,'info')} style={{padding:'4px 10px',border:'1px solid #E5E7EB',borderRadius:6,background:'#fff',fontSize:11,cursor:'pointer'}}>View</button></td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}
